/**
 * Supported locales for MDS components
 * Maps to ISO 639-1 language codes with some regional variants
 */
export const SUPPORTED_LOCALES = [
  'en', // English
  'es', // Español
  'fr', // Français
  'de', // Deutsch
  'it', // Italiano
  'pt', // Português (Brasil)
  'tr', // Türkçe
  'ru', // Русский
  'zh', // 简体中文
  'zh-TW', // 繁體中文
  'ko', // 한국어
  'ja', // 日本語
] as const;

export type SupportedLocale = (typeof SUPPORTED_LOCALES)[number];

/**
 * Base interface for component labels
 */
export interface IComponentLabels {
  [key: string]: string;
}

/**
 * Interface for the labels service
 */
export interface ILabelsService {
  /**
   * Set the current locale globally, and overrides document lang
   * @param locale - The locale to set
   * @example
   * import { labelsService } from '@maersk-global/mds-components-utils';
   * labelsService.setLocale('fr');
   */
  setLocale(locale: SupportedLocale): void;

  /**
   * Get the current active locale
   * Priority: 1. Explicitly set locale, 2. Document lang attribute, 3. Default 'en'
   * @returns The current locale
   * @example
   * import { labelsService } from '@maersk-global/mds-components-utils';
   * const currentLocale = labelsService.getCurrentLocale(); // e.g., 'fr'
   */
  getCurrentLocale(): SupportedLocale;
}

/**
 * Labels service implementation
 * Provides centralized locale management and caching for component labels
 */
class LabelsService implements ILabelsService {
  private currentLocale: SupportedLocale | null = null;

  public getCurrentLocale(): SupportedLocale {
    if (this.currentLocale) {
      return this.currentLocale;
    }

    // Check if we're running in a browser environment (not SSR)
    if (typeof document === 'undefined') {
      return 'en';
    }

    const documentLang = document.documentElement.lang?.toLowerCase() ?? null;
    if (!documentLang) {
      return 'en';
    }

    return this.localeSupported(documentLang);
  }

  public setLocale(locale: SupportedLocale): void {
    this.currentLocale = this.localeSupported(locale);
  }

  private localeSupported(locale: string): SupportedLocale {
    // Check for exact match first (e.g., zh-TW)
    if (SUPPORTED_LOCALES.includes(locale as SupportedLocale)) {
      return locale as SupportedLocale;
    }

    // Extract base language code (e.g., 'en' from 'en-US', 'pt' from 'pt-BR')
    const baseLang = locale.split('-')[0];

    // Check if base language is supported
    if (SUPPORTED_LOCALES.includes(baseLang as SupportedLocale)) {
      return baseLang as SupportedLocale;
    }

    return 'en';
  }
}

/**
 * Singleton instance of the labels service
 */
export const labelsService = new LabelsService();
